function stripAccents(s: string): string {
  return s.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

export function getExtraPlayerImage(name: string): string | undefined {
  if (!name || name === '—') return undefined;
  const keyA = stripAccents(name.toLowerCase().trim());
  if (extraPlayerImages[keyA]) return extraPlayerImages[keyA];
  const parts = keyA.split(' ').filter(Boolean);
  const last = parts[parts.length - 1];
  if (last && last.length > 2 && extraPlayerImages[last]) return extraPlayerImages[last];
  return undefined;
}
